import { getAbsRectCoords } from './bar-encode';

export let bar_subdivider_position = function() {
    const KEY = 'subdivider',
        SUPER_KEY = 'bar';

    this.helpers.position[KEY] = {};

    this.helpers.position[KEY].end = (d, encode) => {
        let end = this.helpers.position[SUPER_KEY].end(d);

        let x, y, width, height;
        if (this.chart.axes.rotated) {
            x = this.scales.y(d.y0);
            y = end.y1;
            (width = 1), (height = this.commonOption.barWidth);
        } else {
            x = end.x1;
            y = this.scales.y(d.y0);
            (width = this.commonOption.barWidth), (height = 1);
        }

        let coords = getAbsRectCoords({ x, y, width, height }, this.builderC.yaxisreversed, this.chart.axes.rotated);
        return coords;
    };
};
